  "ccum-9-social-post": {
    "title": "CCUM 9 | 2D Motion Graphic",
    "sections": [
        {
            "type": "text",
            "paddingTop": 0,
            "html": "<div><span class=\"texteditor-inline-color\" style=\"color:#111111;\"><span style=\"font-size:15px;\" class=\"texteditor-inline-fontsize\"><span style=\"font-family:ttyp; font-weight:700;\">YEAR:</span> <span style=\"font-family:ftnk; font-weight:500;\">2023</span></span></span></div><div><span class=\"texteditor-inline-color\" style=\"color:#111111;\"><span style=\"font-size:15px;\" class=\"texteditor-inline-fontsize\"><span style=\"font-family:ttyp; font-weight:700;\">SOFTWARE:</span> <span style=\"font-family:ftnk; font-weight:500;\">ADOBE ILLUSTRATOR, ADOBE AFTER EFFECTS, ADOBE PHOTOSHOP</span></span></span></div><div style=\"text-align:left;\"><span class=\"texteditor-inline-color\" style=\"color:#111111;\"><span style=\"font-size:14px;\" class=\"texteditor-inline-fontsize\"><span style=\"font-family:ftnk; font-weight:400;\">“Chắp Cánh Ước Mơ 9” is a charity fundraising event organized by student members of the Green Generation Club – RMIT Vietnam. The event aims to support underprivileged children through creative, community-driven initiatives. In its 9th edition, the event successfully raised over 100 million VND through merchandise sales and sponsorship donations. The funds were used to build a completely new restroom facility for Giồng Dinh Primary School in Long An province, contributing to a safer and more hygienic environment for the students.</span></span></span></div>"
        }
    ]
},
  "concert-piece-2d-motion-graphic": {
    "title": "CONCERT PIECE | 2D Motion Graphic",
    "sections": [
        {
            "type": "text",
            "paddingTop": 0,
            "html": "<div><span class=\"texteditor-inline-color\" style=\"color:#111111;\"><span style=\"font-size:15px;\" class=\"texteditor-inline-fontsize\"><span style=\"font-family:ttyp; font-weight:700;\">Year:</span> <span style=\"font-family:ftnk; font-weight:500;\">2023</span></span></span></div><div><span class=\"texteditor-inline-color\" style=\"color:#111111;\"><span style=\"font-size:15px;\" class=\"texteditor-inline-fontsize\"><span style=\"font-family:ttyp; font-weight:700;\">SOFTWARE:</span> <span style=\"font-family:ftnk; font-weight:500;\">ADOBE AFTER EFFECT, ADOBE ILLUSTRATOR</span></span></span></div><div style=\"text-align:left;\"><span class=\"texteditor-inline-color\" style=\"color:#111111;\"><span style=\"font-size:14px;\" class=\"texteditor-inline-fontsize\"><span style=\"font-family:ftnk; font-weight:400;\">Concert Piece is a 2D motion graphic project inspired by the silent dedication of those working behind the scenes to support the artist on stage. The animation centers around a broom character, symbolizing these unsung contributors who quietly ensure every performance runs smoothly. Blending sound design with Japanese-inspired patterns and lines, the piece offers a fresh perspective drawn from verses in </span></span></span></div><div style=\"text-align:left;\"><span class=\"texteditor-inline-color\" style=\"color:#111111;\"><span style=\"font-size:14px;\" class=\"texteditor-inline-fontsize\"><span style=\"font-family:ftnk; font-weight:400;\">Yoko Ono’s “Concert Piece.”</span></span></span></div>"
        },
        {
            "type": "video",
            "paddingTop": 0,
            "iframeSrc": "https://www-ccv.adobe.io/v1/player/ccv/8WA4S3sff7q/embed?bgcolor=%23191919&lazyLoading=true&api_key=BehancePro2View",
            "aspectPadding": 56.25,
            "maxWidth": 1920
        }
    ]
},
